import 'package:flutter/material.dart';
import 'package:flutter_bloc/flutter_bloc.dart';
import 'package:provider/provider.dart';

// Provider model
class CounterProvider extends ChangeNotifier {
  int _count = 0;
  int get count => _count;
  void increment() {
    _count++;
    notifyListeners();
  }
}

// BLoC Cubit
class CounterCubit extends Cubit<int> {
  CounterCubit() : super(0);
  void increment() => emit(state + 1);
}

void main() => runApp(MyApp());

class MyApp extends StatelessWidget {
  @override
  Widget build(BuildContext context) {
    return MultiProvider(
      providers: [
        ChangeNotifierProvider(create: (_) => CounterProvider()),
      ],
      child: MaterialApp(
        title: 'BLoC vs Provider',
        home: DefaultTabController(
          length: 2,
          child: Scaffold(
            appBar: AppBar(
              title: Text('BLoC vs Provider'),
              bottom: TabBar(
                tabs: [
                  Tab(text: 'Provider'),
                  Tab(text: 'BLoC'),
                ],
              ),
            ),
            body: TabBarView(
              children: [
                ProviderPage(),
                BlocPage(),
              ],
            ),
          ),
        ),
      ),
    );
  }
}

class ProviderPage extends StatelessWidget {
  @override
  Widget build(BuildContext context) {
    return Center(
      child: Column(
        mainAxisAlignment: MainAxisAlignment.center,
        children: [
          Text('Provider Counter', style: TextStyle(fontSize: 20)),
          Consumer<CounterProvider>(
            builder: (context, provider, child) => Text('${provider.count}', style: TextStyle(fontSize: 40)),
          ),
          ElevatedButton(
            onPressed: () => context.read<CounterProvider>().increment(),
            child: Text('Increment'),
          ),
        ],
      ),
    );
  }
}

class BlocPage extends StatelessWidget {
  @override
  Widget build(BuildContext context) {
    return BlocProvider(
      create: (_) => CounterCubit(),
      child: Center(
        child: Column(
          mainAxisAlignment: MainAxisAlignment.center,
          children: [
            Text('BLoC Counter', style: TextStyle(fontSize: 20)),
            BlocBuilder<CounterCubit, int>(
              builder: (context, state) => Text('$state', style: TextStyle(fontSize: 40)),
            ),
            ElevatedButton(
              onPressed: () => context.read<CounterCubit>().increment(),
              child: Text('Increment'),
            ),
          ],
        ),
      ),
    );
  }
}
